    return EXIT_SUCCESS;
}


void
runTest( int argc, char** argv)
{
	int rows, cols, size_I, size_R, niter = 10, iter;
	float *I, *J, lambda, q0sqr, sum, sum2, tmp, meanROI,varROI ;

#ifdef CPU
	float Jc, G2, L, num, den, qsqr;
	int *iN,*iS,*jE,*jW, k;
	float *dN,*dS,*dW,*dE;
	float cN,cS,cW,cE,D;
#endif

#ifdef GPU
	// Not used in OpenMP translation, but kept for structure
	float *J_cuda;
    float *C_cuda;
	float *E_C, *W_C, *N_C, *S_C;
#endif

	unsigned int r1, r2, c1, c2;
	float *c;

	// FIX: Re-added argument count check
	if (argc == 9)
	{
		rows = atoi(argv[1]);  //number of rows in the domain
		cols = atoi(argv[2]);  //number of cols in the domain
		if ((rows%16!=0) || (cols%16!=0)){
		fprintf(stderr, "rows and cols must be multiples of 16\n");
		exit(1);
		}
		r1   = atoi(argv[3]);  //y1 position of the speckle
		r2   = atoi(argv[4]);  //y2 position of the speckle
		c1   = atoi(argv[5]);  //x1 position of the speckle
		c2   = atoi(argv[6]);  //x2 position of the speckle
		lambda = atof(argv[7]); //Lambda value
		niter = atoi(argv[8]); //number of iterations

	}
    else{
	usage(argc, argv); // Call usage if argument count is incorrect
    }



	size_I = cols * rows;
    size_R = (r2-r1+1)*(c2-c1+1);

	I = (float *)malloc( size_I * sizeof(float) );
    J = (float *)malloc( size_I * sizeof(float) );
	c  = (float *)malloc(sizeof(float)* size_I) ;


#ifdef CPU

    iN = (int *)malloc(sizeof(unsigned int*) * rows) ;
    iS = (int *)malloc(sizeof(unsigned int*) * rows) ;
    jW = (int *)malloc(sizeof(unsigned int*) * cols) ;
    jE = (int *)malloc(sizeof(unsigned int*) * cols) ;


	dN = (float *)malloc(sizeof(float)* size_I) ;
    dS = (float *)malloc(sizeof(float)* size_I) ;
    dW = (float *)malloc(sizeof(float)* size_I) ;
    dE = (float *)malloc(sizeof(float)* size_I) ;


    for (int i=0; i< rows; i++) {
        iN[i] = i-1;
        iS[i] = i+1;
    }
    for (int j=0; j< cols; j++) {
        jW[j] = j-1;
        jE[j] = j+1;
    }
    iN[0]    = 0;
    iS[rows-1] = rows-1;
    jW[0]    = 0;
    jE[cols-1] = cols-1;

#endif

#ifdef GPU
	// Allocate device memory - not used in OpenMP
	// cudaMalloc((void**)& J_cuda, sizeof(float)* size_I);
    // cudaMalloc((void**)& C_cuda, sizeof(float)* size_I);
	// cudaMalloc((void**)& E_C, sizeof(float)* size_I);
	// cudaMalloc((void**)& W_C, sizeof(float)* size_I);
	// cudaMalloc((void**)& S_C, sizeof(float)* size_I);
	// cudaMalloc((void**)& N_C, sizeof(float)* size_I);
#endif

	printf("Randomizing the input matrix\n");
	//Generate a random matrix
	random_matrix(I, rows, cols);

    for (int k = 0;  k < size_I; k++ ) {
     	J[k] = (float)exp(I[k]) ;
    }
	printf("Start the SRAD main loop\n");
 for (iter=0; iter< niter; iter++){
		sum=0; sum2=0;
        #pragma omp parallel for reduction(+:sum, sum2)
        for (int i=r1; i<=r2; i++) {
            for (int j=c1; j<=c2; j++) {
                tmp   = J[i * cols + j];
                sum  += tmp ;
                sum2 += tmp*tmp;
            }
        }
        meanROI = sum / size_R;
        varROI  = (sum2 / size_R) - meanROI*meanROI;
        q0sqr   = varROI / (meanROI*meanROI);

#ifdef CPU

		#pragma omp parallel for collapse(2)
        for (int i = 0 ; i < rows ; i++) {
            for (int j = 0; j < cols; j++) {

				k = i * cols + j;
				Jc = J[k];

				// directional derivates
                dN[k] = J[iN[i] * cols + j] - Jc;
                dS[k] = J[iS[i] * cols + j] - Jc;
                dW[k] = J[i * cols + jW[j]] - Jc;
                dE[k] = J[i * cols + jE[j]] - Jc;

                G2 = (dN[k]*dN[k] + dS[k]*dS[k]
                    + dW[k]*dW[k] + dE[k]*dE[k]) / (Jc*Jc);

   		        L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

				num  = (0.5*G2) - ((1.0/16.0)*(L*L)) ;
                den  = 1 + (.25*L);
                qsqr = num/(den*den);

                // diffusion coefficent (equ 33)
                den = (qsqr-q0sqr) / (q0sqr * (1+q0sqr)) ;
                c[k] = 1.0 / (1.0+den) ;

                // saturate diffusion coefficent
                if (c[k] < 0) {c[k] = 0;}
                else if (c[k] > 1) {c[k] = 1;}
		}
	}
		#pragma omp parallel for collapse(2)
         for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {

                // current index
                k = i * cols + j;

                // diffusion coefficent
					cN = c[k];
					cS = c[iS[i] * cols + j];
					cW = c[k];
					cE = c[i * cols + jE[j]];

                // divergence (equ 58)
                D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

                // image update (equ 61)
                J[k] = J[k] + 0.25*lambda*D;
            }
	}

#endif // CPU

#ifdef GPU
	// OpenMP implementation of the kernels
	int block_size_x = BLOCK_SIZE;
	int block_size_y = BLOCK_SIZE;

	#pragma omp parallel
	{
		#pragma omp for collapse(2) schedule(static)
		for (int by = 0; by < rows / block_size_y; ++by) {
			for (int bx = 0; bx < cols / block_size_x; ++bx) {
				// Simulate kernel 1
				for (int ty = 0; ty < block_size_y; ++ty) {
					for (int tx = 0; tx < block_size_x; ++tx) {
						// int index = (by * (rows / block_size_y) + bx) * (block_size_x * block_size_y) + (ty * block_size_x + tx);
						int global_idx = (by * block_size_y + ty) * cols + (bx * block_size_x + tx);

						float n, w, e, s, jc, g2, l, num, den_kernel1, qsqr, c_val;

						// Simplified boundary handling for OpenMP
						jc = J[global_idx];

						// North
						if (ty == 0 && by == 0) n = J[global_idx]; else if (ty == 0) n = J[(by - 1) * block_size_y * cols + (bx * block_size_x + tx)]; else n = J[global_idx - cols];
						// South
						if (ty == block_size_y - 1 && by == (rows / block_size_y) - 1) s = J[global_idx]; else if (ty == block_size_y - 1) s = J[(by + 1) * block_size_y * cols + (bx * block_size_x + tx)]; else s = J[global_idx + cols];
						// West
						if (tx == 0 && bx == 0) w = J[global_idx]; else if (tx == 0) w = J[(by * block_size_y + ty) * cols + (bx - 1) * block_size_x]; else w = J[global_idx - 1];
						// East
						if (tx == block_size_x - 1 && bx == (cols / block_size_x) - 1) e = J[global_idx]; else if (tx == block_size_x - 1) e = J[(by * block_size_y + ty) * cols + (bx + 1) * block_size_x]; else e = J[global_idx + 1];

						n -= jc;
						s -= jc;
						w -= jc;
						e -= jc;

						g2 = (n * n + s * s + w * w + e * e) / (jc * jc);
						l = (n + s + w + e) / jc;

						num = (0.5 * g2) - ((1.0 / 16.0) * (l * l));
						den_kernel1 = 1 + (.25 * l);
						qsqr = num / (den_kernel1 * den_kernel1);

						den_kernel1 = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
						c_val = 1.0 / (1.0 + den_kernel1);

						if (c_val < 0) c[global_idx] = 0;
						else if (c_val > 1) c[global_idx] = 1;
						else c[global_idx] = c_val;
					}
				}
			}
		}
	}

	#pragma omp parallel
	{
		#pragma omp for collapse(2) schedule(static)
		for (int by = 0; by < rows / block_size_y; ++by) {
			for (int bx = 0; bx < cols / block_size_x; ++bx) {
				// Simulate kernel 2
				for (int ty = 0; ty < block_size_y; ++ty) {
					for (int tx = 0; tx < block_size_x; ++tx) {
						int global_idx = (by * block_size_y + ty) * cols + (bx * block_size_x + tx);

						float cc, cn, cs, ce, cw, d_sum;

						// Simplified boundary handling for OpenMP
						cc = c[global_idx];

						// North coefficient
						if (ty == 0 && by == 0) cn = c[global_idx]; else if (ty == 0) cn = c[(by - 1) * block_size_y * cols + (bx * block_size_x + tx)]; else cn = c[global_idx - cols];
						// South coefficient
						if (ty == block_size_y - 1 && by == (rows / block_size_y) - 1) cs = c[global_idx]; else if (ty == block_size_y - 1) cs = c[(by + 1) * block_size_y * cols + (bx * block_size_x + tx)]; else cs = c[global_idx + cols];
						// West coefficient
						if (tx == 0 && bx == 0) cw = c[global_idx]; else if (tx == 0) cw = c[(by * block_size_y + ty) * cols + (bx - 1) * block_size_x]; else cw = c[global_idx - 1];
						// East coefficient
						if (tx == block_size_x - 1 && bx == (cols / block_size_x) - 1) ce = c[global_idx]; else if (tx == block_size_x - 1) ce = c[(by * block_size_y + ty) * cols + (bx + 1) * block_size_x]; else ce = c[global_idx + 1];

						// Need to re-calculate directional derivatives for divergence
						float n_deriv, s_deriv, w_deriv, e_deriv;
						float jc = J[global_idx];

						if (ty == 0 && by == 0) n_deriv = 0; else if (ty == 0) n_deriv = J[(by - 1) * block_size_y * cols + (bx * block_size_x + tx)] - jc; else n_deriv = J[global_idx - cols] - jc;
						if (ty == block_size_y - 1 && by == (rows / block_size_y) - 1) s_deriv = 0; else if (ty == block_size_y - 1) s_deriv = J[(by + 1) * block_size_y * cols + (bx * block_size_x + tx)] - jc; else s_deriv = J[global_idx + cols] - jc;
						if (tx == 0 && bx == 0) w_deriv = 0; else if (tx == 0) w_deriv = J[(by * block_size_y + ty) * cols + (bx - 1) * block_size_x] - jc; else w_deriv = J[global_idx - 1] - jc;
						if (tx == block_size_x - 1 && bx == (cols / block_size_x) - 1) e_deriv = 0; else if (tx == block_size_x - 1) e_deriv = J[(by * block_size_y + ty) * cols + (bx + 1) * block_size_x] - jc; else e_deriv = J[global_idx + 1] - jc;


						d_sum = cn * n_deriv + cs * s_deriv + cw * w_deriv + ce * e_deriv;

						J[global_idx] = J[global_idx] + 0.25 * lambda * d_sum;
					}
				}
			}
		}
	}

#endif
}

    // cudaThreadSynchronize(); // Not needed for OpenMP

#ifdef OUTPUT
    //Printing output
		printf("Printing Output:\n");
    for( int i = 0 ; i < rows ; i++){
		for ( int j = 0 ; j < cols ; j++){
         printf("%.5f ", J[i * cols + j]);
		}
     printf("\n");
   }
#endif

	printf("Computation Done\n");

	free(I);
	free(J);
#ifdef CPU
	free(iN); free(iS); free(jW); free(jE);
    free(dN); free(dS); free(dW); free(dE);
#endif
#ifdef GPU
    // cudaFree(C_cuda); // Not used in OpenMP
